local dialog = nil

local function getChildWindow(window, name, type)
    local child = window:getChildWindow(name, type)
    if not child then
        error("CustomDialog must have" .. name .. " child window.")
    end
    return child
end

local GUICustomDialog = class("GUICustomDialog", IGUILayout)

function GUICustomDialog:onLoad()
    self.contents = {}
    self.contentView = nil
    self.customParams = nil
    self.leftClickListener = nil
    self.rightClickListener = nil
    self.closeClickListener = nil
    local name = string.gsub(self.__name, ".json", "-")
    self.llContent = getChildWindow(self, name .. "Content", GUIType.Layout)
    self.tvTitleText = getChildWindow(self, name .. "Title-Text", GUIType.StaticText)
    self.btnClose = getChildWindow(self, name .. "Close", GUIType.Button)
    self.tvContentText = getChildWindow(self, name .. "Content-Text", GUIType.StaticText)
    self.ivExtraIcon = getChildWindow(self, name .. "Extra-Icon", GUIType.StaticImage)
    self.tvExtraText = getChildWindow(self, name .. "Extra-Text", GUIType.StaticText)
    self.btnLeftButton = getChildWindow(self, name .. "Left-Button", GUIType.Button)
    self.ivLeftIcon = getChildWindow(self, name .. "Left-Icon", GUIType.StaticImage)
    self.btnRightButton = getChildWindow(self, name .. "Right-Button", GUIType.Button)
    self.ivRightIcon = getChildWindow(self, name .. "Right-Icon", GUIType.StaticImage)
    self.btnClose:registerEvent(GUIEvent.ButtonClick, function()
        if self.closeClickListener then
            self.closeClickListener()
        end
        self:hide()
        SoundUtil.playSound(SoundType.ClosePanel)
    end)
    self.btnLeftButton:registerEvent(GUIEvent.ButtonClick, function()
        if self.leftClickListener ~= nil then
            local close = self.leftClickListener() ---返回true拦截dialog不关闭
            if not close then
                self:hide()
            end
        else
            self:hide()
        end
        SoundUtil.playSound(SoundType.ClosePanel)
    end)
    self.btnRightButton:registerEvent(GUIEvent.ButtonClick, function()
        if self.rightClickListener ~= nil then
            local close = self.rightClickListener() ---返回true拦截dialog不关闭
            if not close then
                self:hide()
            end
        else
            self:hide()
        end
        SoundUtil.playSound(SoundType.ClosePanel)
    end)
    self.leftButtonPos = self.btnLeftButton:GetXPosition()
    self.leftIconPos = self.ivLeftIcon:GetXPosition()
    self.rightButtonPos = self.btnRightButton:GetXPosition()
    self.rightIconPos = self.ivRightIcon:GetXPosition()
end

function GUICustomDialog:setDefault()
    self.customParams = nil
    self.leftClickListener = nil
    self.rightClickListener = nil
    self.closeClickListener = nil
    self.tvTitleText:SetText(Lang:getString("gui_dialog_tip_title_tip"))
    self.btnClose:SetVisible(true)
    self.tvContentText:SetText("")
    self.ivExtraIcon:SetVisible(false)
    self.ivLeftIcon:SetVisible(false)
    self:setLeftText(Lang:getString("gui_dialog_tip_btn_cancel"))
    self:setLeftDisable(true)

    self.ivLeftIcon:SetArea({ 0, 15 }, { 0, 0 }, { 0, 34 }, { 0, 38 })

    self.ivRightIcon:SetVisible(false)
    self:setRightText(Lang:getString("gui_dialog_tip_btn_sure"))
    self.disableTime = 0
    if self.contentView ~= nil then
        self.contentView:hide()
        self.contentView = nil
    end
    if self.hideTimer then
        LuaTimer:cancel(self.hideTimer)
    end
    if self.disableTimer then
        LuaTimer:cancel(self.disableTimer)
    end
end

function GUICustomDialog:hide()
    self.disableTime = self.disableTime or 0
    if self.disableTime > 0 then
        print("GUICustomDialog:hide " .. self.disableTime)
        return
    end
    if self:isAlwaysShow() then
        return
    end
    if self:isShow() then
        self.root:SetVisible(false)
        self:onHide()
    end
end

function GUICustomDialog:onHide()
    self:setDefault()
end

function GUICustomDialog:builder()
    self:setDefault()
end

function GUICustomDialog:setContentView(view)
    self.contentView = self.contents[view.__name]
    if self.contentView ~= nil then
        self.contentView:show()
    else
        HostApi.log("GUICustomDialog [can't find content view --- name:" .. view.__name .. "]", 1)
    end
end

local function setButtonUI(button, icon, iconPos)
    if not button:IsVisible() then
        return
    end
    local oldOffsetY = button:GetRenderOffset()
    if icon:IsVisible() then
        local offset = icon:GetPixelSize().x / 2
        button:SetRenderOffset({ x = offset, y = oldOffsetY })
        if #button:GetText() == 0 then
            icon:SetHorizontalAlignment(HorizontalAlignment.Center)
            icon:SetXPosition({ 0, 0 })
        else
            icon:SetHorizontalAlignment(HorizontalAlignment.Left)
            icon:SetXPosition(iconPos)
        end
    else
        button:SetRenderOffset({ x = 0, y = oldOffsetY })
    end
end

function GUICustomDialog:setUI()
    if self.btnLeftButton:IsVisible() and self.btnRightButton:IsVisible() then
        self.btnLeftButton:SetHorizontalAlignment(HorizontalAlignment.Left)
        self.btnLeftButton:SetXPosition(self.leftButtonPos)
        self.btnRightButton:SetHorizontalAlignment(HorizontalAlignment.Right)
        self.btnRightButton:SetXPosition(self.rightButtonPos)
    elseif self.btnLeftButton:IsVisible() then
        self.btnLeftButton:SetHorizontalAlignment(HorizontalAlignment.Center)
        self.btnLeftButton:SetXPosition({ 0, 0 })
    elseif self.btnRightButton:IsVisible() then
        self.btnRightButton:SetHorizontalAlignment(HorizontalAlignment.Center)
        self.btnRightButton:SetXPosition({ 0, 0 })
    end
    setButtonUI(self.btnLeftButton, self.ivLeftIcon, self.leftIconPos)
    setButtonUI(self.btnRightButton, self.ivRightIcon, self.rightIconPos)
    if self.contentView ~= nil then
        self.tvContentText:SetText("")
        self.ivExtraIcon:SetVisible(false)
    end
end

function GUICustomDialog:setLeftText(text)
    if not text or #text == 0 then
        self.btnLeftButton:SetText("")
        self.btnLeftButton:SetVisible(self.ivLeftIcon:IsVisible())
    else
        self.btnLeftButton:SetVisible(true)
        self.btnLeftButton:SetText(Lang:getString(text))
    end
end

function GUICustomDialog:setRightText(text)
    if not text or #text == 0 then
        self.btnRightButton:SetText("")
        self.btnRightButton:SetVisible(self.ivRightIcon:IsVisible())
    else
        self.btnRightButton:SetVisible(true)
        self.btnRightButton:SetText(Lang:getString(text))
    end
end

function GUICustomDialog:setLeftDisable(value)
    if self.btnLeftButton then
        self.btnLeftButton:SetEnabled(value)
    end
end

function GUICustomDialog:setLeftIconArea(x, y, w, h)
    self.ivLeftIcon:SetArea(x, y, w, h)
end

