---设置显示时间
---@time s 显示时间
function CustomDialog.setShowTime(time, showCountDown)
    dialog.countDownTime = time

    dialog.hideTimer = LuaTimer:scheduleTimer(function()
        if dialog.countDownTime <= 0 then
            dialog:hide()
            return
        end
        if showCountDown then
            dialog:setRightText(string.format("%s(%d)",
                    Lang:getString("gui_dialog_tip_btn_sure"), dialog.countDownTime))
        end
        dialog.countDownTime = dialog.countDownTime - 1
    end, 1000, time + 1)

    return CustomDialog
end

---设置不能点击时间
---@time s 时间
function CustomDialog.setDisableTime(time)
    dialog.disableTime = time

    dialog.disableTimer = LuaTimer:schedule(function()
        if dialog.disableTime <= 0 then
            if dialog.disableTimer then
                LuaTimer:cancel(dialog.disableTimer)
            end
            return
        end
        dialog.disableTime = dialog.disableTime - 1
    end, 0, 1000)

    return CustomDialog
end

