---初始化对话框，可是设置使用的布局json
---@name 对话框的json文件名，默认CustomDialog.json
function initCustomDialog(name)
    if dialog ~= nil then
        return
    end
    dialog = GUICustomDialog.new(name)
end

---构造一个自定义对话框内容体
---@class 内容体的类名，必须继承IGUILayout
---@name 内容体的json文件名
function buildCustomDialogContent(class, name)
    local content = class.new(name, dialog.llContent)
    content:hide()
    dialog.contents[name] = content
    return content
end
